// Package dsamport was generated by IDLC from DsamPort.idl.
// It is part of module dsam.
// The remaining comment is for module dsam.
package dsamport

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40411/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40411/idl"
)

// Success code
const SUCCESS int32 = 0

// Error codes
const (
	SETTINGS_INVALID     int32 = 1
	SSH_DPA_PORT_INVALID int32 = 2
	SSH_DPA_PORT_IN_USE  int32 = 3
)

// DSAM port interface
type DsamPort interface {
	idl.Object

	// Get current port info.
	//
	//	@return Port info
	GetInfo(ctx context.Context) (Info, error)

	// Get current port settings.
	//
	//	@return  Port settings.
	GetSettings(ctx context.Context) (Settings, error)

	// Set port settings.
	//
	//	@param settings  Port settings
	//	@return SUCCESS if no error occurred or one of the defined error codes
	SetSettings(ctx context.Context, settings Settings) (int32, error)

	// Get the number of the ttyUSB device.
	//
	// NOTE: This function is only used internally and is not available via JSON-RPC.
	//
	//	@return ttyUSB device number
	GetTtyUsbNumber(ctx context.Context) (int32, error)

	// Set the state of the port.
	//
	// NOTE: This function is only used internally and is not available via JSON-RPC.
	//
	//	@param state  Port state
	SetState(ctx context.Context, state State) error
}

// Serial device interface type
type DeviceInterfaceType int

const (
	DEV_IFTYPE_AUTO DeviceInterfaceType = iota // auto detect
	DEV_IFTYPE_DTE                             // DTE (Data Terminal Equipment) device detected
	DEV_IFTYPE_DCE                             // DCE (Data Communications Equipment) device detected
)

// Parity mode
type Parity int

const (
	PARITY_NONE Parity = iota // No parity (implies 8 data bits)
	PARITY_ODD                // Odd parity (implies 7 data bits)
	PARITY_EVEN               // Even parity (implies 7 data bits)
)

// Flow control type
type FlowControl int

const (
	FLOW_CTRL_NONE     FlowControl = iota // No flow control
	FLOW_CTRL_HARDWARE                    // Hardware flow control
	FLOW_CTRL_SOFTWARE                    // Software flow control
)

// Port state
type State int

const (
	STATE_AVAILABLE State = iota // no clients connected to port
	STATE_OCCUPIED               // at least one client connected, more clients allowed
	STATE_BUSY                   // no more clients allowed
)

// Port info
type Info struct {
	DsamNumber int32               // DSAM number (1-based)
	PortNumber int32               // port number (1-based)
	Connected  bool                // true if serial device is connected
	DevIfType  DeviceInterfaceType // serial device interface type if connected is true
	State      State               // state of the port
}

// Port settings
type Settings struct {
	Name              string              // Port name
	DevIfType         DeviceInterfaceType // Port interface type (allows forcing the interface type)
	BaudRate          int32               // Baud rate
	Parity            Parity              // Parity mode
	StopBits          int32               // Number of stop bits (1 or 2)
	FlowCtrl          FlowControl         // Flow control type
	BreakDurationMs   int32               // Length of BREAK signal duration in milliseconds
	SshDpaPortEnabled bool                // true if dedicated SSH DPA port is enabled
	SshDpaPort        int32               // SSH DPA port number
	AllowSharedAccess bool                // Allow more than one user to connect to this port
}

// Event that is sent when the port info has changed
type InfoChangedEvent interface {
	userevent.UserEvent
	OldInfo() Info    // Old port info
	NewInfo() Info    // New port info
	PortName() string // current port name
	isInfoChangedEvent()
}

// Event that is sent when the port settings have changed
type SettingsChangedEvent interface {
	userevent.UserEvent
	DsamNumber() int32     // DSAM number
	PortNumber() int32     // port number
	OldSettings() Settings // Old port settings
	NewSettings() Settings // New port settings
	isSettingsChangedEvent()
}
